    businesses = json.load(f)

with open(reviews_path, 'r') as f:
    reviews = json.load(f)

def check_open_after_6pm(time_str):
    '''Check if business is open after 6 PM'''
    if time_str == "Open 24 hours":
        return True
    if time_str == "Closed":
        return False

    # Check for PM times after 6 PM
    if "PM" in time_str:
        # Extract hour number
        import re
        hour_match = re.search(r'(\d+)(?::\d+)?\s*PM', time_str, re.IGNORECASE)
        if hour_match:
            hour = int(hour_match.group(1))
            # Convert to 24-hour (6 PM = 18, 7 PM = 19, etc.)
            if hour < 12:
                hour += 12
            if hour > 18:  # After 6 PM
                return True
            if hour == 18 and ':' in time_str:
                # Check if it's 6:something PM
                minute_match = re.search(r'6:(\d+)\s*PM', time_str, re.IGNORECASE)
                if minute_match and int(minute_match.group(1)) > 0:
                    return True

    return False

# Step 1: Calculate average ratings
ratings_by_business = defaultdict(list)
for r in reviews:
    gid = r['gmap_id']
    ratings_by_business[gid].append(int(r['rating']))

avg_ratings = {}
for gid, ratings in ratings_by_business.items():
    avg_ratings[gid] = {
        'avg': sum(ratings) / len(ratings),
        'count': len(ratings)
    }

# Step 2: Find businesses open after 6 PM on weekdays
weekdays = set(['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'])
candidates = []

for b in businesses:
    gid = b['gmap_id']
    hours_str = b.get('hours', '')
    if not hours_str or hours_str == 'None':
